// // Asynchronous reset causes the flip-flop to hold its current state on the positive edge of the clock
module DFlipFlop (
    input clk,
    input reset,
    input D,
    output reg Q
);
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            Q <= 0;
        end else begin
            Q <= D;
        end
    end
endmodule
